-- =====================================================================-- 0014_grants_revokes.sql-- Política de privilégios: revogar SELECT direto em tabelas sensíveis,-- conceder em views; manter INSERT/UPDATE em base apenas onde RLS gateia.-- =====================================================================-- ---------- Sensíveis: SELECT só via views ----------revoke select on public.assignments from authenticated;revoke select on public.responses   from authenticated;revoke select on public.comments    from authenticated;-- ---------- Sensíveis: mutações só via service_role ----------revoke insert, update, delete on public.responses from authenticated;revoke insert, update, delete on public.comments  from authenticated;-- ---------- Concessões em views ----------grant select on public.assignments_admin   to authenticated;grant select on public.assignments_safe    to authenticated;grant select on public.comments_published  to authenticated;-- ---------- Catálogos globais ----------grant select on public.assessment_methods   to authenticated;grant select on public.relationship_types   to authenticated;-- ---------- Schema usage ----------grant usage on schema public to authenticated;-- ---------- Defesa adicional: nenhum acesso para anon ----------revoke all on all tables in schema public from anon;revoke all on all sequences in schema public from anon;revoke all on all functions in schema public from anon;-- Reset garantido em mutations administrativas (templates, cycles, etc.)-- são gateadas por RLS, mas grants base devem existir.grant insert, update on public.tenants                       to authenticated;grant insert, update, delete on public.tenant_memberships    to authenticated;grant insert, update, delete on public.people                to authenticated;grant insert, update, delete on public.templates             to authenticated;grant insert, update, delete on public.template_relationship_rules to authenticated;grant insert, update, delete on public.competencies          to authenticated;grant insert, update, delete on public.questionnaires        to authenticated;grant insert, update, delete on public.questions             to authenticated;grant insert, update, delete on public.questionnaire_questions to authenticated;grant insert, update on public.cycles                        to authenticated;grant insert, update, delete on public.cycle_participants    to authenticated;grant insert, update on public.assignments                   to authenticated;grant insert on public.integration_exports                   to authenticated;-- SELECT direto em tabelas administrativas (não sensíveis)grant select on  public.tenants,  public.tenant_memberships,  public.people,  public.templates,  public.template_relationship_rules,  public.competencies,  public.questionnaires,  public.questions,  public.questionnaire_questions,  public.cycles,  public.cycle_participants,  public.score_snapshots,  public.participant_result_profiles,  public.integration_exports,  public.audit_logto authenticated;